interface AccountStore {
    Money getBalance(String accountId);
    void setBalance(String accountId, Money balance);
    boolean markRequestProcessed(String accountId, String clientRequestId);
}

final class SharedPrefsAccountStore implements AccountStore {
    private static final String PREFS = "bank_account_store_v1";
    private static final String KEY_BAL_PREFIX = "bal_";
    private static final String KEY_REQ_PREFIX = "req_";

    private final SharedPreferences prefs;

    public SharedPrefsAccountStore(Context context) {
        this.prefs = context.getSharedPreferences(PREFS, Context.MODE_PRIVATE);
    }

    @Override
    public Money getBalance(String accountId) {
        String raw = prefs.getString(KEY_BAL_PREFIX + accountId, "0.00");
        try {
            return Money.of(raw);
        } catch (Exception e) {
            return Money.zero();
        }
    }

    @Override
    public void setBalance(String accountId, Money balance) {
        prefs.edit().putString(KEY_BAL_PREFIX + accountId, balance.asBigDecimal().toPlainString()).apply();
    }

    @Override
    public boolean markRequestProcessed(String accountId, String clientRequestId) {
        String key = KEY_REQ_PREFIX + accountId + "_" + clientRequestId;
        synchronized (this) {
            if (prefs.getBoolean(key, false)) return false;
            prefs.edit().putBoolean(key, true).apply();
            return true;
        }
    }
}

