final class TransactionProcessor {
    private final AccountStore store;
    private final SecurityGate securityGate;

    public TransactionProcessor(AccountStore store, SecurityGate securityGate) {
        this.store = store;
        this.securityGate = securityGate;
    }

    public synchronized TransactionResult process(TransactionRequest req) {
        if (!securityGate.isUserAuthorizedForSensitiveAction()) {
            return new TransactionResult(false, "Not authorized", null, null, null);
        }
        if (req == null || req.amount == null || req.type == null) {
            return new TransactionResult(false, "Invalid request", null, null, null);
        }
        if (req.amount.compareTo(Money.zero()) <= 0) {
            return new TransactionResult(false, "Amount must be greater than zero", null, null, null);
        }

        String fromId = req.fromAccountId;
        String toId = req.toAccountId;

        if (req.type == TransactionType.DEBIT) {
            if (fromId == null || fromId.trim().isEmpty()) {
                return new TransactionResult(false, "Missing source account", null, null, null);
            }
            if (!store.markRequestProcessed(fromId, req.clientRequestId)) {
                Money fb = store.getBalance(fromId);
                Money tb = toId != null ? store.getBalance(toId) : null;
                return new TransactionResult(true, "Duplicate request ignored", "dup-" + req.clientRequestId, fb, tb);
            }
            Money fromBal = store.getBalance(fromId);
            if (fromBal.compareTo(req.amount) < 0) {
                return new TransactionResult(false, "Insufficient funds", null, fromBal, toId != null ? store.getBalance(toId) : null);
            }
            Money newFrom = fromBal.minus(req.amount);
            store.setBalance(fromId, newFrom);

            Money newTo = null;
            if (toId != null && !toId.trim().isEmpty()) {
                Money toBal = store.getBalance(toId);
                newTo = toBal.plus(req.amount);
                store.setBalance(toId, newTo);
            }
            return new TransactionResult(true, "OK", UUID.randomUUID().toString(), newFrom, newTo);
        } else {
            if (toId == null || toId.trim().isEmpty()) {
                return new TransactionResult(false, "Missing destination account", null, null, null);
            }
            if (!store.markRequestProcessed(toId, req.clientRequestId)) {
                Money tb = store.getBalance(toId);
                Money fb = fromId != null ? store.getBalance(fromId) : null;
                return new TransactionResult(true, "Duplicate request ignored", "dup-" + req.clientRequestId, fb, tb);
            }
            Money toBal = store.getBalance(toId);
            Money newTo = toBal.plus(req.amount);
            store.setBalance(toId, newTo);

            Money newFrom = null;
            if (fromId != null && !fromId.trim().isEmpty()) {
                Money fromBal = store.getBalance(fromId);
                newFrom = fromBal.minus(req.amount);
                store.setBalance(fromId, newFrom);
            }
            return new TransactionResult(true, "OK", UUID.randomUUID().toString(), newFrom, newTo);
        }
    }
}

