final class BankingRepository {
    private final AccountStore store;
    private final TransactionProcessor processor;
    private final ExecutorService executor = Executors.newSingleThreadExecutor();

    public interface Callback<T> {
        void onResult(T result);
    }

    public BankingRepository(Context context) {
        this.store = new SharedPrefsAccountStore(context);
        this.processor = new TransactionProcessor(store, new SimpleSecurityGate(context));
    }

    public Money getBalance(String accountId) {
        return store.getBalance(accountId);
    }

    public void setInitialBalanceIfEmpty(String accountId, Money initial) {
        Money existing = store.getBalance(accountId);
        if (existing == null) existing = Money.zero();
        if (existing.asBigDecimal().compareTo(BigDecimal.ZERO) == 0) {
            store.setBalance(accountId, initial);
        }
    }

    public void processAsync(final TransactionRequest req, final Callback<TransactionResult> cb) {
        executor.execute(new Runnable() {
            @Override
            public void run() {
                TransactionResult r = processor.process(req);
                if (cb != null) cb.onResult(r);
            }
        });
    }

    public TransactionResult process(TransactionRequest req) {
        return processor.process(req);
    }
}

