package com.example.bankapp.ui;

import android.app.Activity;
import android.content.Context;
import android.os.Bundle;
import android.os.Handler;
import android.os.Looper;
import android.text.InputType;
import android.view.Gravity;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.LinearLayout;
import android.widget.TextView;

import com.example.bankapp.BankingRepository;
import com.example.bankapp.Money;
import com.example.bankapp.TransactionRequest;
import com.example.bankapp.TransactionResult;
import com.example.bankapp.TransactionType;

public class AccountActivity extends Activity {
    private BankingRepository repo;
    private Handler mainHandler;

    private String checkingId = "checking";
    private String savingsId = "savings";

    private TextView checkingBalance;
    private TextView savingsBalance;
    private TextView status;

    private EditText amountInput;
    private Button transferToSavings;
    private Button transferToChecking;
    private Button refresh;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        repo = new BankingRepository(getApplicationContext());
        mainHandler = new Handler(Looper.getMainLooper());

        repo.setInitialBalanceIfEmpty(checkingId, Money.of("1000.00"));
        repo.setInitialBalanceIfEmpty(savingsId, Money.of("2500.00"));

        setContentView(buildContentView(this));
        refreshBalances();
    }

    private View buildContentView(Context ctx) {
        int pad = dp(ctx, 16);

        LinearLayout root = new LinearLayout(ctx);
        root.setOrientation(LinearLayout.VERTICAL);
        root.setPadding(pad, pad, pad, pad);
        root.setGravity(Gravity.TOP);

        TextView title = new TextView(ctx);
        title.setText("Accounts");
        title.setTextSize(20f);

        checkingBalance = new TextView(ctx);
        savingsBalance = new TextView(ctx);

        amountInput = new EditText(ctx);
        amountInput.setHint("Amount (e.g., 25.00)");
        amountInput.setInputType(InputType.TYPE_CLASS_NUMBER | InputType.TYPE_NUMBER_FLAG_DECIMAL);

        transferToSavings = new Button(ctx);
        transferToSavings.setText("Transfer Checking → Savings");

        transferToChecking = new Button(ctx);
        transferToChecking.setText("Transfer Savings → Checking");

        refresh = new Button(ctx);
        refresh.setText("Refresh");

        status = new TextView(ctx);
        status.setText("");

        root.addView(title);
        root.addView(spacer(ctx, 12));
        root.addView(checkingBalance);
        root.addView(savingsBalance);
        root.addView(spacer(ctx, 12));
        root.addView(amountInput);
        root.addView(spacer(ctx, 12));
        root.addView(transferToSavings);
        root.addView(transferToChecking);
        root.addView(spacer(ctx, 8));
        root.addView(refresh);
        root.addView(spacer(ctx, 12));
        root.addView(status);

        transferToSavings.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                doTransfer(checkingId, savingsId);
            }
        });

        transferToChecking.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                doTransfer(savingsId, checkingId);
            }
        });

        refresh.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                refreshBalances();
                status.setText("");
            }
        });

        return root;
    }

    private void doTransfer(String fromId, String toId) {
        String amt = amountInput.getText() != null ? amountInput.getText().toString().trim() : "";
        if (amt.isEmpty()) {
            status.setText("Enter an amount.");
            return;
        }

        Money amount;
        try {
            amount = Money.of(amt);
        } catch (Exception e) {
            status.setText("Invalid amount.");
            return;
        }

        TransactionRequest req = new TransactionRequest.Builder()
                .fromAccountId(fromId)
                .toAccountId(toId)
                .amount(amount)
                .type(TransactionType.DEBIT)
                .memo("User transfer")
                .build();

        setButtonsEnabled(false);
        status.setText("Processing...");

        repo.processAsync(req, new BankingRepository.Callback<TransactionResult>() {
            @Override
            public void onResult(final TransactionResult result) {
                mainHandler.post(new Runnable() {
                    @Override
                    public void run() {
                        setButtonsEnabled(true);
                        if (result.success) {
                            status.setText("Success. Txn: " + result.transactionId);
                        } else {
                            status.setText("Failed: " + result.message);
                        }
                        refreshBalances();
                    }
                });
            }
        });
    }

    private void refreshBalances() {
        Money cb = repo.getBalance(checkingId);
        Money sb = repo.getBalance(savingsId);
        checkingBalance.setText("Checking (" + checkingId + "): " + (cb != null ? cb.format() : "$0.00"));
        savingsBalance.setText("Savings (" + savingsId + "): " + (sb != null ? sb.format() : "$0.00"));
    }

    private void setButtonsEnabled(boolean enabled) {
        transferToSavings.setEnabled(enabled);
        transferToChecking.setEnabled(enabled);
        refresh.setEnabled(enabled);
    }

    private static View spacer(Context ctx, int dp) {
        View v = new View(ctx);
        v.setLayoutParams(new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                dp(ctx, dp)
        ));
        return v;
    }

    private static int dp(Context ctx, int dp) {
        float density = ctx.getResources().getDisplayMetrics().density;
        return (int) (dp * density + 0.5f);
    }
}

